// Render template — load cold-outreach-v1.md and substitute variables.
const fs = require('fs');
const path = require('path');
const tpl = fs.readFileSync(path.resolve(process.env.TEMPLATE_DIR || './email-templates', 'cold-outreach-v1.md'), 'utf8');
const lead = items[0].json;
const frameworkByCountry = { 'United Kingdom': 'FCA', 'United Arab Emirates': 'VARA', 'Singapore': 'MAS' };
const framework = frameworkByCountry[lead.country] || 'MiCA';
const replacements = {
  '{{contact_name}}': (lead.contact_name || '').split(' ')[0] || 'there',
  '{{company_name}}': lead.company_name,
  '{{country}}': lead.country,
  '{{compliance_framework}}': framework,
  '{{sender.first_name}}': 'Giorgio',
  '{{sender.title}}': 'Head of Sales',
  '{{sender.company}}': 'BlockchainAnalysis.io',
  '{{sender.calendar_url}}': 'https://cal.com/blockchainanalysisdemo/intro',
  '{{compliance.dpo_email}}': process.env.DPO_EMAIL,
  '{{compliance.unsubscribe_url}}': `${process.env.UNSUBSCRIBE_BASE_URL}/${lead.unsubscribe_token}`,
  '{{compliance.company_legal_name}}': process.env.COMPANY_LEGAL_NAME,
  '{{compliance.company_address}}': process.env.COMPANY_ADDRESS,
};
let rendered = tpl;
for (const [k, v] of Object.entries(replacements)) rendered = rendered.split(k).join(v ?? '');
const [subjectLine, ...rest] = rendered.split('\n');
return [{ json: { ...lead, subject: subjectLine.replace(/^Subject:\s*/, ''), body: rest.join('\n').trim(), template_used: 'cold-outreach-v1' } }];
